hgc_intro.solution:
Lemma hgc_intro : forall h,
  heap_affine h ->
  \GC h.
Proof using.
  introv M. unfold hgc. exists (= h).
  exists Fmap.empty h. splits.
  { hnf. split. { auto. } { intros h' ->. auto. } }
  { auto. }
  { applys Fmap.disjoint_empty_l. }
  { rewrite Fmap.union_empty_l. auto. }
Qed.
